import{_ as t,c as o,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"ToS 警告: 账户风险与安全实践 | Antigravity Auth","description":"学习 Antigravity Auth 插件的使用风险和账户安全实践。了解高风险场景、影子封禁机制和速率限制区别，掌握多账户策略、使用量控制和账户热身方法。","frontmatter":{"title":"ToS 警告: 账户风险与安全实践 | Antigravity Auth","sidebarTitle":"别让账户被封","subtitle":"ToS 警告: 账户风险与安全实践","description":"学习 Antigravity Auth 插件的使用风险和账户安全实践。了解高风险场景、影子封禁机制和速率限制区别，掌握多账户策略、使用量控制和账户热身方法。","tags":["FAQ","风险提示","账户安全"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"zh/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"zh/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}'),r={name:"zh/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function e(n,l,s,d,h,g){return a(),o("div",null,[...l[0]||(l[0]=[i('<h1 id="tos-警告" tabindex="-1">ToS 警告 <a class="header-anchor" href="#tos-警告" aria-label="Permalink to &quot;ToS 警告&quot;">​</a></h1><p>学完这课，你能了解使用 Antigravity Auth 插件可能面临的风险，以及如何保护你的 Google 账户安全。</p><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你在考虑使用 Antigravity Auth 插件访问 Google Antigravity 的 AI 模型，但有些担忧：</p><ul><li>看到社区有人报告账户被封禁或影子封禁</li><li>担心使用非官方工具违反 Google 的服务条款</li><li>不确定是否应该用新账户还是老账户</li><li>想知道如何降低风险</li></ul><p>这些担忧是合理的。使用任何非官方工具都有一定风险，本文将帮你了解具体的风险点和应对策略。</p><h2 id="什么时候需要看这一课" tabindex="-1">什么时候需要看这一课 <a class="header-anchor" href="#什么时候需要看这一课" aria-label="Permalink to &quot;什么时候需要看这一课&quot;">​</a></h2><ul><li><strong>安装插件前</strong>：了解风险后再决定是否使用</li><li><strong>选择账户时</strong>：决定用哪个 Google 账户进行认证</li><li><strong>遇到封禁时</strong>：了解可能的原因和预防措施</li><li><strong>新用户注册时</strong>：避免高风险操作模式</li></ul><hr><h2 id="核心风险概述" tabindex="-1">核心风险概述 <a class="header-anchor" href="#核心风险概述" aria-label="Permalink to &quot;核心风险概述&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">重要警告</p><p><strong>使用此插件可能会违反 Google 的服务条款（Terms of Service）。</strong></p><p>少数用户报告他们的 Google 账户被封禁或影子封禁（Shadow Ban，即限制访问但没有明确通知）。</p><p><strong>使用此插件即表示你接受以下声明：</strong></p><ol><li>这是非官方工具，未获得 Google 认可或背书</li><li>你的 Google 账户可能会被暂停或永久封禁</li><li>你自行承担使用此插件的所有风险和后果</li></ol></div><h3 id="什么是影子封禁" tabindex="-1">什么是影子封禁？ <a class="header-anchor" href="#什么是影子封禁" aria-label="Permalink to &quot;什么是影子封禁？&quot;">​</a></h3><p><strong>影子封禁（Shadow Ban）</strong> 是 Google 对可疑账户采取的一种限制措施。与直接封禁不同，影子封禁不会显示明确的错误信息，而是：</p><ul><li>API 请求返回 403 或 429 错误</li><li>配额显示可用，但实际无法调用</li><li>其他账户正常工作，只有被标记的账户受影响</li></ul><p>影子封禁通常持续时间较长（几天到几周），且无法通过申诉恢复。</p><hr><h2 id="高风险场景" tabindex="-1">高风险场景 <a class="header-anchor" href="#高风险场景" aria-label="Permalink to &quot;高风险场景&quot;">​</a></h2><p>以下场景会显著增加账户被标记或封禁的风险：</p><h3 id="🚨-场景-1-全新的-google-账户" tabindex="-1">🚨 场景 1：全新的 Google 账户 <a class="header-anchor" href="#🚨-场景-1-全新的-google-账户" aria-label="Permalink to &quot;🚨 场景 1：全新的 Google 账户&quot;">​</a></h3><p><strong>风险等级：极高</strong></p><p>全新注册的 Google 账户使用本插件，被封禁的概率非常高。原因：</p><ul><li>新账户缺少历史行为数据，容易被 Google 的滥用检测系统标记</li><li>大量 API 调用在新账户上会被视为异常行为</li><li>Google 对新账户的审核更严格</li></ul><p><strong>建议</strong>：不要为此插件专门创建新账户。</p><h3 id="🚨-场景-2-新账户-pro-ultra-订阅" tabindex="-1">🚨 场景 2：新账户 + Pro/Ultra 订阅 <a class="header-anchor" href="#🚨-场景-2-新账户-pro-ultra-订阅" aria-label="Permalink to &quot;🚨 场景 2：新账户 + Pro/Ultra 订阅&quot;">​</a></h3><p><strong>风险等级：极高</strong></p><p>新注册的账户并立即订阅 Google 的 Pro 或 Ultra 服务，经常被标记并封禁。原因：</p><ul><li>订阅后的高用量模式在新账户上看起来像滥用</li><li>Google 对新付费用户的审核更严格</li><li>这种模式与正常用户的成长路径差异太大</li></ul><p><strong>建议</strong>：让账户先&quot;自然成长&quot;一段时间（至少几个月），再考虑订阅。</p><h3 id="🟡-场景-3-短时间内大量请求" tabindex="-1">🟡 场景 3：短时间内大量请求 <a class="header-anchor" href="#🟡-场景-3-短时间内大量请求" aria-label="Permalink to &quot;🟡 场景 3：短时间内大量请求&quot;">​</a></h3><p><strong>风险等级：高</strong></p><p>在短时间内发起大量 API 请求，或频繁使用并行代理/多会话，会触发速率限制和滥用检测。原因：</p><ul><li>OpenCode 的请求模式比原生应用更密集（工具调用、重试、流式传输等）</li><li>高并发请求会触发 Google 的保护机制</li></ul><p><strong>建议</strong>：</p><ul><li>控制请求频率和并发数</li><li>避免同时启动多个并行代理</li><li>使用多账户轮换分散请求</li></ul><h3 id="🟡-场景-4-使用唯一的-google-账户" tabindex="-1">🟡 场景 4：使用唯一的 Google 账户 <a class="header-anchor" href="#🟡-场景-4-使用唯一的-google-账户" aria-label="Permalink to &quot;🟡 场景 4：使用唯一的 Google 账户&quot;">​</a></h3><p><strong>风险等级：中</strong></p><p>如果你只有一个 Google 账户，且依赖它访问关键服务（Gmail、Drive 等），风险较高。原因：</p><ul><li>账户被封禁会影响你的日常工作</li><li>无法通过申诉恢复</li><li>备用方案缺失</li></ul><p><strong>建议</strong>：使用一个不依赖关键服务的独立账户。</p><hr><h2 id="最佳实践建议" tabindex="-1">最佳实践建议 <a class="header-anchor" href="#最佳实践建议" aria-label="Permalink to &quot;最佳实践建议&quot;">​</a></h2><h3 id="✅-推荐做法" tabindex="-1">✅ 推荐做法 <a class="header-anchor" href="#✅-推荐做法" aria-label="Permalink to &quot;✅ 推荐做法&quot;">​</a></h3><p><strong>1. 使用已建立的 Google 账户</strong></p><p>优先选择已使用一段时间（建议 6 个月以上）的 Google 账户：</p><ul><li>有正常的 Google 服务使用历史（Gmail、Drive、Google Search 等）</li><li>没有历史违规记录</li><li>账户绑定了手机号并完成验证</li></ul><p><strong>2. 配置多个账户</strong></p><p>添加多个 Google 账户，通过轮换分散请求：</p><ul><li>至少配置 2-3 个账户</li><li>使用 <code>account_selection_strategy: &quot;hybrid&quot;</code> 策略（默认）</li><li>遇到限速时自动切换账户</li></ul><p><strong>3. 控制 使用量</strong></p><ul><li>避免短时间内密集请求</li><li>减少并行代理的数量</li><li>在 <code>antigravity.json</code> 中设置 <code>max_rate_limit_wait_seconds: 0</code> 快速失败而不是重试</li></ul><p><strong>4. 监控账户状态</strong></p><p>定期检查账户状态：</p><ul><li>查看 <code>~/.config/opencode/antigravity-accounts.json</code> 中的 <code>rateLimitResetTimes</code></li><li>启用调试日志：<code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>遇到 403/429 错误时暂停使用 24-48 小时</li></ul><p><strong>5. 先在官方界面&quot;热身&quot;</strong></p><p>社区用户报告的有效方法：</p><ol><li>在浏览器中登录 <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>运行几个简单的提示（如「你好」、「2+2 等于几」）</li><li>5-10 次成功调用后，再使用插件</li></ol><p><strong>原理</strong>：通过官方界面使用账户会让 Google 认为这是正常用户行为，降低被标记的风险。</p><h3 id="❌-避免的做法" tabindex="-1">❌ 避免的做法 <a class="header-anchor" href="#❌-避免的做法" aria-label="Permalink to &quot;❌ 避免的做法&quot;">​</a></h3><ul><li>❌ 专门为此插件创建全新的 Google 账户</li><li>❌ 在新注册的账户上立即订阅 Pro/Ultra</li><li>❌ 用唯一的关键服务账户（如工作邮箱）</li><li>❌ 触发 429 限制后反复重试</li><li>❌ 同时启动大量并行代理</li><li>❌ 提交 <code>antigravity-accounts.json</code> 到版本控制</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-我的账户被封禁了-能申诉吗" tabindex="-1">Q: 我的账户被封禁了，能申诉吗？ <a class="header-anchor" href="#q-我的账户被封禁了-能申诉吗" aria-label="Permalink to &quot;Q: 我的账户被封禁了，能申诉吗？&quot;">​</a></h3><p><strong>A: 不能。</strong></p><p>如果是通过本插件触发 Google 的滥用检测导致的封禁或影子封禁，通常无法通过申诉恢复。原因：</p><ul><li>封禁是基于 API 使用模式自动触发的</li><li>Google 对非官方工具的使用持严格态度</li><li>申诉时需要说明工具用途，但本插件本身就可能被视为违规</li></ul><p><strong>建议</strong>：</p><ul><li>使用其他未受影响的账户</li><li>如果所有账户都被封禁，直接使用 <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>避免在被封禁的账户上继续尝试</li></ul><h3 id="q-使用本插件一定会被封禁吗" tabindex="-1">Q: 使用本插件一定会被封禁吗？ <a class="header-anchor" href="#q-使用本插件一定会被封禁吗" aria-label="Permalink to &quot;Q: 使用本插件一定会被封禁吗？&quot;">​</a></h3><p><strong>A: 不一定。</strong></p><p>大多数用户使用本插件没有遇到问题。风险取决于：</p><ul><li>账户年龄和历史行为</li><li>使用频率和请求模式</li><li>是否遵循最佳实践</li></ul><p><strong>风险评估</strong>：</p><ul><li>老账户 + 适度使用 + 多账户轮换 → 低风险</li><li>新账户 + 密集请求 + 单账户 → 高风险</li></ul><h3 id="q-影子封禁和速率限制有什么区别" tabindex="-1">Q: 影子封禁和速率限制有什么区别？ <a class="header-anchor" href="#q-影子封禁和速率限制有什么区别" aria-label="Permalink to &quot;Q: 影子封禁和速率限制有什么区别？&quot;">​</a></h3><p><strong>A: 本质不同，恢复方式也不同。</strong></p><table tabindex="0"><thead><tr><th>特征</th><th>影子封禁</th><th>速率限制（429）</th></tr></thead><tbody><tr><td>触发原因</td><td>滥用检测，被标记为可疑</td><td>请求频率超过配额</td></tr><tr><td>错误码</td><td>403 或静默失败</td><td>429 Too Many Requests</td></tr><tr><td>持续时间</td><td>几天到几周</td><td>几小时到一天</td></tr><tr><td>恢复方法</td><td>无法恢复，需用其他账户</td><td>等待重置或切换账户</td></tr><tr><td>是否可预防</td><td>遵循最佳实践降低风险</td><td>控制请求频率</td></tr></tbody></table><h3 id="q-可以用企业-google-账户吗" tabindex="-1">Q: 可以用企业 Google 账户吗？ <a class="header-anchor" href="#q-可以用企业-google-账户吗" aria-label="Permalink to &quot;Q: 可以用企业 Google 账户吗？&quot;">​</a></h3><p><strong>A: 不推荐。</strong></p><p>企业账户通常绑定关键服务和数据，封禁影响更严重。此外：</p><ul><li>企业账户的审核更严格</li><li>可能违反企业的 IT 政策</li><li>风险由个人承担，但影响团队</li></ul><p><strong>建议</strong>：使用个人账户。</p><h3 id="q-多账户能完全避免封禁吗" tabindex="-1">Q: 多账户能完全避免封禁吗？ <a class="header-anchor" href="#q-多账户能完全避免封禁吗" aria-label="Permalink to &quot;Q: 多账户能完全避免封禁吗？&quot;">​</a></h3><p><strong>A: 不能完全避免，但能降低影响。</strong></p><p>多账户的作用：</p><ul><li>分散请求，降低单个账户触发限制的概率</li><li>一个账户被封禁，其他账户仍然可用</li><li>遇到限制时自动切换，提高可用性</li></ul><p><strong>但多账户不是&quot;护身符&quot;</strong>：</p><ul><li>如果所有账户都触发滥用检测，可能全部被封禁</li><li>不要滥用多账户进行密集请求</li><li>每个账户仍需遵循最佳实践</li></ul><hr><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>阅读完本课，你应该知道：</p><ul><li>[ ] 使用本插件可能违反 Google ToS，风险自负</li><li>[ ] 新账户 + Pro/Ultra 订阅是高风险场景</li><li>[ ] 推荐使用已建立的 Google 账户</li><li>[ ] 配置多个账户可以分散风险</li><li>[ ] 账户被封禁后无法申诉恢复</li><li>[ ] 控制请求频率和使用量很重要</li></ul><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>本课介绍了使用 Antigravity Auth 插件可能面临的风险：</p><ol><li><strong>核心风险</strong>：可能违反 Google ToS，账户可能被封禁或影子封禁</li><li><strong>高风险场景</strong>：新账户、新账户 + 订阅、密集请求、单一关键账户</li><li><strong>最佳实践</strong>：使用老账户、配置多账户、控制使用量、监控状态、先&quot;热身&quot;</li><li><strong>常见问题</strong>：无法申诉、风险因人而异、多账户可降低影响</li></ol><p>使用本插件前，请仔细评估风险。如果你无法接受账户可能被封禁的后果，建议直接使用 <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>。</p><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><p>本课内容基于项目 README 文档的风险警告部分（README.md:23-40），不涉及具体代码实现。</p><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>ToS 警告声明</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const c=t(r,[["render",e]]);export{p as __pageData,c as default};
